-- FSI_DEMO_DB_V3.CAPITAL_MARKETS.POSITIONS

CREATE OR REPLACE TABLE FSI_DEMO_DB_V3.CAPITAL_MARKETS.POSITIONS (

    POSITION_ID VARCHAR(30) NOT NULL,
    ACCOUNT_ID VARCHAR(20),
    SECURITY_ID VARCHAR(20),
    POSITION_DATE DATE,
    QUANTITY NUMBER(15,4),
    AVERAGE_COST NUMBER(18,4),
    MARKET_VALUE NUMBER(18,2),
    UNREALIZED_PNL NUMBER(18,2),
    REALIZED_PNL NUMBER(18,2),
    WEIGHT_PCT NUMBER(7,4),
    SECTOR_EXPOSURE VARCHAR(50),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (POSITION_ID)

);





